return [{
  json: {
    workflow_id: 'CWF-210',
    vein: 'narrative_vein',
    dossier_id: $json.dossier_id || 'TEST-DOSSIER',
    topic_finalization_packet: $json.topic_finalization_packet || {},
    research_synthesis_packet: $json.research_synthesis_packet || {},
    route_id: $json.route_id || 'ROUTE_PHASE1_STANDARD',
    execution_timestamp: new Date().toISOString(),
    narrative_constraints: {
      tone: 'engaging',
      target_duration_seconds: 60,
      audience_level: 'general',
      hook_type: 'question_or_statement'
    }
  }
}];

const topic = $json.topic_finalization_packet || {};
const research = $json.research_synthesis_packet || {};

const script_brief = {
  brief_id: 'SBF-' + Date.now(),
  topic_statement: topic.finalized_topic || 'Topic',
  main_claim: research.main_claim || '',
  supporting_claims: (research.supporting_claims || []).map(c => c.claim),
  evidence_summary: research.evidence_confidence || 0.75,
  hook_direction: 'Start with surprising fact about: ' + (topic.finalized_topic || 'topic'),
  body_points: [
    { point: 'What is ' + (topic.finalized_topic || 'it') + '?', evidence_ref: 'research' },
    { point: 'Why does it matter?', evidence_ref: 'audience_pain' },
    { point: 'How can viewers use this?', evidence_ref: 'practical_application' }
  ],
  closing_intent: 'Call to action or thought-provoking question',
  narrative_angle: 'Educational + actionable insight',
  risk_flags: research.contradictions_found ? ['evidence_contradiction_exists'] : []
};

return [{
  json: {
    ...$json,
    script_brief: script_brief,
    brief_ready: true
  }
}];

const brief = $json.script_brief || {};
const target_duration = $json.narrative_constraints?.target_duration_seconds || 60;
const words_per_second = 2.5; // speaking pace
const target_words = target_duration * words_per_second;

const draft_text_parts = [
  `**HOOK:** ${brief.hook_direction || 'Opening statement'}`,
  `**BODY:**`,
  ...(brief.body_points || []).map((p, i) => `${i+1}. ${p.point}`),
  `**CLOSING:** ${brief.closing_intent || 'Closing statement'}`
].join('\n\n');

const script_draft = {
  draft_id: 'DRF-' + Date.now(),
  title: 'Script: ' + (brief.topic_statement || 'Untitled'),
  hook: brief.hook_direction || '',
  body: {
    sections: brief.body_points || [],
    estimated_words: Math.round(target_words),
    estimated_duration_seconds: target_duration
  },
  closing: brief.closing_intent || '',
  narrative_angle: brief.narrative_angle || '',
  evidence_references: brief.supporting_claims || [],
  draft_status: 'INITIAL_GENERATION',
  confidence: 0.75,
  structure: {
    hook_status: 'generated',
    body_status: 'structured',
    closing_status: 'generated'
  }
};

return [{
  json: {
    ...$json,
    script_draft: script_draft,
    draft_created: true
  }
}];

const draft = $json.script_draft || {};

const hook_audit = {
  hook_text: draft.hook || '',
  hook_strength: draft.hook ? 0.80 : 0.4,
  hook_type_detected: 'question_or_statement',
  qualities: {
    is_specific: true,
    creates_curiosity: true,
    signals_value: true
  },
  audit_result: draft.hook && draft.hook.length > 20 ? 'PASS' : 'NEEDS_WORK'
};

const structure_audit = {
  has_hook: !!draft.hook,
  has_body: (draft.body && draft.body.sections && draft.body.sections.length > 0),
  has_closing: !!draft.closing,
  structure_completeness: 1.0,
  audit_result: (!!draft.hook && !!draft.closing) ? 'PASS' : 'INCOMPLETE'
};

return [{
  json: {
    ...$json,
    hook_audit: hook_audit,
    structure_audit: structure_audit,
    audit_result: (hook_audit.audit_result === 'PASS' && structure_audit.audit_result === 'PASS') ? 'READY_FOR_DEBATE' : 'NEEDS_WORK'
  }
}];

const draft = $json.script_draft || {};
const topic = $json.topic_finalization_packet || {};
const research = $json.research_synthesis_packet || {};
const hook_audit = $json.hook_audit || {};
const structure_audit = $json.structure_audit || {};

const draft_packet = {
  instance_id: 'SDP-' + Date.now(),
  artifact_family: 'script_draft_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-210-Script-Generation',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: $json.audit_result === 'READY_FOR_DEBATE' ? 'CREATED' : 'CREATED_NEEDS_WORK',
  payload: {
    // 1. CORE NARRATIVE CONTENT
    narrative: {
      title: draft.title || 'Untitled Script',
      hook: {
        text: draft.hook || '',
        direction: draft.hook || 'Hook needed',
        audit: {
          strength: hook_audit.hook_strength || 0.5,
          is_specific: hook_audit.qualities?.is_specific || false,
          creates_curiosity: hook_audit.qualities?.creates_curiosity || false,
          signals_value: hook_audit.qualities?.signals_value || false,
          result: hook_audit.audit_result || 'NEEDS_WORK'
        }
      },
      body: {
        sections: (draft.body?.sections || []).map((s, idx) => ({
          order: idx + 1,
          point: s.point || '',
          evidence_ref: s.evidence_ref || ''
        })),
        estimated_word_count: draft.body?.estimated_words || 150,
        estimated_duration_seconds: draft.body?.estimated_duration_seconds || 60,
        structure_completeness: structure_audit.structure_completeness || 0.75
      },
      closing: {
        text: draft.closing || '',
        intent: draft.closing_intent || 'Closing statement needed'
      }
    },

    // 2. CONTEXT & METADATA
    context: {
      narrative_angle: draft.narrative_angle || 'Educational + actionable',
      tone: $json.narrative_constraints?.tone || 'engaging',
      target_audience: $json.narrative_constraints?.audience_level || 'general',
      sourced_from: {
        topic_packet_id: topic.instance_id || 'unknown',
        research_packet_id: research.instance_id || 'unknown'
      },
      topic_statement: topic.finalized_topic || 'Unknown topic',
      research_confidence: research.evidence_confidence || 0.75
    },

    // 3. EVIDENCE & REFERENCES
    evidence: {
      main_claim: research.main_claim || '',
      supporting_claims: (research.supporting_claims || []).map(c => ({
        claim: typeof c === 'string' ? c : c.claim || '',
        confidence: typeof c === 'object' ? c.confidence : 0.75
      })),
      evidence_references: (draft.evidence_references || []).map(ref => ({
        reference: ref,
        source: 'research_packet'
      })),
      unresolved_gaps: research.gaps_identified || [],
      contradiction_flags: research.contradictions_found ? ['evidence_contradiction_detected'] : []
    },

    // 4. QUALITY METRICS & AUDIT
    quality: {
      draft_confidence: draft.confidence || 0.75,
      completeness: (structure_audit.structure_completeness || 0.75),
      hook_strength: hook_audit.hook_strength || 0.5,
      hook_audit: {
        text: hook_audit.hook_text || '',
        strength: hook_audit.hook_strength || 0.5,
        type_detected: hook_audit.hook_type_detected || 'unknown',
        qualities: hook_audit.qualities || {},
        result: hook_audit.audit_result || 'NEEDS_WORK'
      },
      structure_audit: {
        has_hook: structure_audit.has_hook || false,
        has_body: structure_audit.has_body || false,
        has_closing: structure_audit.has_closing || false,
        body_section_count: (draft.body?.sections || []).length,
        completeness: structure_audit.structure_completeness || 0.75,
        result: structure_audit.audit_result || 'INCOMPLETE'
      },
      overall_audit_result: $json.audit_result || 'INCOMPLETE'
    },

    // 5. STATUS & NEXT STEPS
    status: {
      creation_status: 'INITIAL_GENERATION',
      generation_phase: 'first_draft',
      ready_for_debate: $json.audit_result === 'READY_FOR_DEBATE',
      ready_for_refinement: false,
      next_workflow: 'CWF-220-Script-Debate',
      escalation_needed: $json.audit_result !== 'READY_FOR_DEBATE',
      retry_possible: true,
      decision_path: $json.audit_result === 'READY_FOR_DEBATE' ? 'PROCEED_TO_DEBATE' : 'NEEDS_WORK_BEFORE_DEBATE'
    }
  }
};

return [{ json: draft_packet }];

try {
  const packet = $json;

  // Validate envelope
  if (!packet.instance_id || !packet.artifact_family) throw new Error('Missing packet envelope fields');
  if (packet.artifact_family !== 'script_draft_packet') throw new Error('Invalid artifact family');
  if (!packet.dossier_ref) throw new Error('Missing dossier reference');

  // Validate payload structure (hierarchical)
  const payload = packet.payload;
  if (!payload.narrative) throw new Error('Missing narrative section');
  if (!payload.context) throw new Error('Missing context section');
  if (!payload.evidence) throw new Error('Missing evidence section');
  if (!payload.quality) throw new Error('Missing quality section');
  if (!payload.status) throw new Error('Missing status section');

  // Validate critical narrative fields
  if (!payload.narrative.title) throw new Error('Title is required');
  if (!payload.narrative.hook?.text) throw new Error('Hook text is required');
  if (!payload.narrative.body?.sections || payload.narrative.body.sections.length === 0) throw new Error('Body sections required');
  if (!payload.narrative.closing?.text) throw new Error('Closing text required');

  // Validate references are present
  if (!payload.context.sourced_from?.topic_packet_id) throw new Error('Topic packet reference missing');

  const validation_result = {
    validation_result: 'SUCCESS',
    packet_valid: true,
    validation_checks: {
      envelope: 'PASS',
      payload_structure: 'PASS',
      narrative_content: 'PASS',
      references: 'PASS',
      quality_metrics: 'PASS'
    },
    packet: packet
  };

  return [{ json: validation_result }];
} catch (e) {
  return [{ json: { 
    validation_result: 'ERROR', 
    error: e.message,
    validation_checks: { error: e.message },
    packet: $json 
  } }];
}

const dossier_delta = {
  dossier_id: $json.dossier_ref,
  namespace: 'script',
  mutation_timestamp: new Date().toISOString(),
  mutation_owner: 'SE-N8N-CWF-210',
  mutation_type: 'append_to_array',
  target_field: 'script_draft_packets',
  audit_entry: {
    event: 'SCRIPT_DRAFT_GENERATED',
    workflow_id: 'CWF-210',
    packet_id: $json.instance_id,
    status: $json.status,
    audit_result: $json.payload.audit_result
  }
};

return [{ json: { dossier_delta: dossier_delta, write_to_dossier: true } }];

const packet_index_row = {
  packet_id: $json.instance_id,
  dossier_id: $json.dossier_ref,
  packet_type: $json.artifact_family,
  version: $json.schema_version,
  workflow_id: 'CWF-210',
  child_workflow_id: 'SE-N8N-CWF-210-Script-Generation',
  created_at: $json.created_at,
  file_path: 'C:/ShadowEmpire/n8n_user/packets/' + $json.instance_id + '.json',
  status: $json.status
};

return [{ json: { packet_index_row: packet_index_row, write_to_index: true } }];

const is_valid = $json.validation_result === 'SUCCESS';
const is_ready = $json.packet?.payload?.status?.ready_for_debate || false;

return [{
  json: {
    workflow_id: 'CWF-210',
    workflow_name: 'script_generation',
    execution_status: 'SUCCESS',
    validation_status: $json.validation_result,
    next_workflow: 'CWF-220',

    script_draft_packet: $json.packet || $json,

    // Summary for routing
    summary: {
      title: $json.packet?.payload?.narrative?.title || 'Unknown',
      hook_strength: $json.packet?.payload?.quality?.hook_strength || 0,
      completion_percentage: (($json.packet?.payload?.narrative?.body?.sections?.length || 0) > 0 ? 100 : 50),
      audit_result: $json.packet?.payload?.quality?.overall_audit_result || 'INCOMPLETE'
    },

    // Routing decision
    routing: {
      ready_for_debate: is_ready,
      ready_for_refinement: false,
      escalation_needed: !is_ready,
      next_stage: is_ready ? 'CWF-220-Script-Debate' : 'Return-for-Rework',
      decision: is_ready ? 'PROCEED_TO_DEBATE' : 'NEEDS_WORK_BEFORE_DEBATE'
    },

    // Lineage tracking
    lineage: {
      created_by: 'CWF-210-Script-Generation',
      timestamp: new Date().toISOString(),
      dossier_id: $json.packet?.dossier_ref,
      packet_id: $json.packet?.instance_id
    }
  }
}];
